import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  getChatChannelMeta,
} from "openclaw/plugin-sdk/core";

const meta = getChatChannelMeta(
  "pulseboard" as Parameters<typeof getChatChannelMeta>[0],
);

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      ...meta,
      id: "pulseboard",
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with boards and DMs.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      resolveAccount: () => ({
        accountId: "default",
        enabled: true,
        configured: false,
      }),
      defaultAccountId: () => "default",
      isConfigured: () => false,
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] starting PulseBoard provider`,
        );
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
        text: text ?? "",
      });
    },
  },
});

